class Solution:
    def evalRPN(self, tokens: List[str]) -> int:
        
        stack = []

        for char in tokens:
            if char == "+":
                stack.append(stack.pop() + stack.pop())
            elif char == "-":
                a, b = stack.pop(), stack.pop()
                stack.append(b - a)
            elif char == "*":
                stack.append(stack.pop() * stack.pop())
            elif char == "/":
                a, b = stack.pop(), stack.pop()
                stack.append(int(b/a))
            else:
                stack.append(int(char))
        
        return stack[0]

        # Solution Description: Reverse Polish Notation places operators after their operands, which makes it perfectly suited to a stack. Scan the tokens left to right. Every number gets pushed onto the stack. When an operator appears, pop the top two numbers, apply the operator, and push the result back — that result becomes an operand for a later operation. After processing all tokens, exactly one number remains on the stack: the final answer. The one subtlety is operand order — since the stack is LIFO, the first value popped is the right-hand operand, which matters for subtraction and division.                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   